/**
 * Professional Geometric Solver for SafetyStudio CAD.
 * This utility modifies sketch coordinates to satisfy geometric constraints.
 */

// Helper: Validate if any existing persistent dimension is violated
export const validateConstraints = (oldSketches, newSketches, dimensions, fixedPoints, referenceVertices = [], SCALE_M = 50, ignoreDimId = null) => {
   const errors = [];

   // Check Dimensions
   for (const d of dimensions) {
      if (ignoreDimId && d.id === ignoreDimId) continue;

      const s1 = newSketches.find(s => s.id === d.v1.sketchId);
      const s2 = newSketches.find(s => s.id === d.v2.sketchId);
      // Wait: references aren't in newSketches, they are read-only anchors
      const isRef1 = d.v1.type === 'reference' || d.v1.type === 'origin';
      const isRef2 = d.v2.type === 'reference' || d.v2.type === 'origin';
      if (!isRef1 && !s1) continue;
      if (!isRef2 && !s2) continue;

      const getCoord = (s, part) => {
         if (!s) return null;
         if (s.type === 'line') {
            if (part === 'start') return {x: s.points[0], y: s.points[1]};
            if (part === 'end') return {x: s.points[2], y: s.points[3]};
            if (part === 'mid') return {x: (s.points[0]+s.points[2])/2, y: (s.points[1]+s.points[3])/2};
         }
         if (s.type === 'circle') {
            if (part === 'center') return {x: s.center[0], y: s.center[1]};
            if (part === 'rad') return {x: s.center[0] + s.radius, y: s.center[1]};
         }
         if (s.type === 'rect') {
           const [x1, y1] = s.start;
           const [x2, y2] = s.end;
           if (part === 'start' || part === 'p1') return {x: x1, y: y1};
           if (part === 'p2') return {x: x2, y: y1};
           if (part === 'p3' || part === 'end') return {x: x2, y: y2};
           if (part === 'p4') return {x: x1, y: y2};
           if (part === 'center') return {x: (x1+x2)/2, y: (y1+y2)/2};
           if (part === 'mid_top') return {x: (x1+x2)/2, y: y1};
           if (part === 'mid_bottom') return {x: (x1+x2)/2, y: y2};
           if (part === 'mid_left') return {x: x1, y: (y1+y2)/2};
           if (part === 'mid_right') return {x: x2, y: (y1+y2)/2};
         }
         return null;
      };
      
      const p1 = isRef1 ? {x: d.v1.x, y: d.v1.y} : getCoord(s1, d.v1.part);
      const p2 = isRef2 ? {x: d.v2.x, y: d.v2.y} : getCoord(s2, d.v2.part);
      if (!p1 || !p2) continue;

      const curDist = Math.sqrt(Math.pow(p2.x-p1.x,2) + Math.pow(p2.y-p1.y,2)) / SCALE_M;
      if (Math.abs(curDist - d.value) > 0.001) { // 1mm tolerance
         errors.push(`Violates Dimension: ${d.label} (Would become ${curDist.toFixed(3)})`);
      }
   }

   // Check Fixed Points
   for (const f of fixedPoints) {
       const oldS = oldSketches.find(s => s.id === f.sketchId);
       const newS = newSketches.find(s => s.id === f.sketchId);
       if (oldS && newS) {
           const getCoord = (s, part) => {
              if (s.type === 'line') {
                 if (part === 'start') return {x: s.points[0], y: s.points[1]};
                 if (part === 'end') return {x: s.points[2], y: s.points[3]};
              } else if (s.type === 'circle') {
                 if (part === 'center') return {x: s.center[0], y: s.center[1]};
              } else if (s.type === 'rect') {
                 if (part === 'start') return {x: s.start[0], y: s.start[1]};
                 if (part === 'end') return {x: s.end[0], y: s.end[1]};
              }
              return {x: 0, y: 0};
           };
           const pOld = getCoord(oldS, f.part);
           const pNew = getCoord(newS, f.part);
           if (Math.abs(pOld.x - pNew.x) > 0.001 || Math.abs(pOld.y - pNew.y) > 0.001) {
               errors.push(`Violates Anchor on previously fixed point`);
           }
       }
   }

   return errors;
};

export const isFullyConstrained = (s, dimensions, fixedPoints) => {
   // Simple heuristic: attached to at least 1 anchor and has dimensional constraints
   const hasAnchor = fixedPoints.some(f => f.sketchId === s.id);
   const numDims = dimensions.filter(d => d.v1.sketchId === s.id || d.v2.sketchId === s.id).length;
   
   if (s.type === 'line') return hasAnchor && numDims >= 1; 
   if (s.type === 'circle') return hasAnchor && numDims >= 1;
   if (s.type === 'rect') return hasAnchor && numDims >= 2;
   return false;
};

export const applyConstraint = (sketches, type, vA, vB = null, fixedPoints = [], dimensions = [], SCALE_M = 50, referenceVertices = []) => {
  const updated = [...sketches];
  let error = null;

  // Prioritize moving the unconstrained component
  let v1 = vA, v2 = vB;
  const isFixed = (v) => v && (v.type === 'origin' || v.type === 'reference' || fixedPoints.some(f => f.sketchId === v.sketchId && f.part === v.part) || (v.sketchId && isFullyConstrained(updated.find(s => s.id === v.sketchId) || {}, dimensions, fixedPoints)));
  if (v2 && isFixed(vB) && !isFixed(vA)) {
     v1 = vB; v2 = vA;
  }

  // Helper: Find sketch index by ID
  const findIdx = (id) => updated.findIndex(s => s.id === id);

  // Helper: Move ALL points at (oldX, oldY) to (newX, newY) to maintain connectivity (Polygons)
  const moveAllCoincident = (oldX, oldY, newX, newY, ignoreIds = []) => {
    updated.forEach((s, i) => {
       if (ignoreIds.includes(s.id)) return;
       const ns = { ...s };
       let changed = false;
       const thresh = 0.005;

       if (ns.type === 'line') {
          // Check start, end, and mid
          if (Math.abs(ns.points[0] - oldX) < thresh && Math.abs(ns.points[1] - oldY) < thresh) {
             ns.points = [newX, newY, ns.points[2], ns.points[3]];
             changed = true;
          } else if (Math.abs(ns.points[2] - oldX) < thresh && Math.abs(ns.points[3] - oldY) < thresh) {
             ns.points = [ns.points[0], ns.points[1], newX, newY];
             changed = true;
          } else {
             const midX = (ns.points[0] + ns.points[2]) / 2;
             const midY = (ns.points[1] + ns.points[3]) / 2;
             if (Math.abs(midX - oldX) < thresh && Math.abs(midY - oldY) < thresh) {
                const dx = newX - oldX;
                const dy = newY - oldY;
                ns.points = [ns.points[0] + dx, ns.points[1] + dy, ns.points[2] + dx, ns.points[3] + dy];
                changed = true;
             }
          }
       } else if (ns.type === 'circle') {
          if (Math.abs(ns.center[0] - oldX) < thresh && Math.abs(ns.center[1] - oldY) < thresh) {
             ns.center = [newX, newY];
             changed = true;
          }
       } else if (ns.type === 'rect') {
          // Check corners and midpoints
          const x1 = ns.start[0], y1 = ns.start[1], x2 = ns.end[0], y2 = ns.end[1];
          const pts = [
            [x1, y1], [x2, y1], [x2, y2], [x1, y2], // corners
            [(x1+x2)/2, y1], [(x1+x2)/2, y2], [x1, (y1+y2)/2], [x2, (y1+y2)/2], // midpoints
            [(x1+x2)/2, (y1+y2)/2] // center
          ];
          if (pts.some(p => Math.abs(p[0] - oldX) < thresh && Math.abs(p[1] - oldY) < thresh)) {
             const dx = newX - oldX;
             const dy = newY - oldY;
             ns.start = [ns.start[0] + dx, ns.start[1] + dy];
             ns.end   = [ns.end[0] + dx, ns.end[1] + dy];
             changed = true;
          }
       }
       if (changed) updated[i] = ns;
    });
  };

  switch (type) {
    case 'vertical':
    case 'horizontal': {
      if (v1.type === 'origin') { error = `Cannot make Origin ${type}.`; break; }
      const idx = findIdx(v1.sketchId);
      if (idx === -1) break;
      const s = { ...updated[idx] };
      if (s.type === 'line') {
        const x1 = s.points[0], y1 = s.points[1], x2 = s.points[2], y2 = s.points[3];
        const isFix = (x, y, part) => (x === 0 && y === 0) || fixedPoints.some(f => f.sketchId === s.id && f.part === part);
        const fix1 = isFix(x1, y1, 'start');
        const fix2 = isFix(x2, y2, 'end');

        let pivotX, pivotY;
        if (fix1 && !fix2) {
           pivotX = x1; pivotY = y1;
        } else if (!fix1 && fix2) {
           pivotX = x2; pivotY = y2;
        } else {
           pivotX = (x1 + x2) / 2; pivotY = (y1 + y2) / 2;
        }

        const len = Math.sqrt(Math.pow(x2-x1, 2) + Math.pow(y2-y1, 2));
        if (type === 'vertical') {
           if (fix1) {
              const ny = pivotY + (y2 > y1 ? len : -len);
              moveAllCoincident(x2, y2, pivotX, ny, [s.id]);
              s.points = [x1, y1, pivotX, ny];
           } else if (fix2) {
              const ny = pivotY + (y1 > y2 ? len : -len);
              moveAllCoincident(x1, y1, pivotX, ny, [s.id]);
              s.points = [pivotX, ny, x2, y2];
           } else {
              moveAllCoincident(x1, y1, pivotX, pivotY - len/2, [s.id]);
              moveAllCoincident(x2, y2, pivotX, pivotY + len/2, [s.id]);
              s.points = [pivotX, pivotY - len/2, pivotX, pivotY + len/2];
           }
        } else {
           // horizontal
           if (fix1) {
              const nx = pivotX + (x2 > x1 ? len : -len);
              moveAllCoincident(x2, y2, nx, pivotY, [s.id]);
              s.points = [x1, y1, nx, pivotY];
           } else if (fix2) {
              const nx = pivotX + (x1 > x2 ? len : -len);
              moveAllCoincident(x1, y1, nx, pivotY, [s.id]);
              s.points = [nx, pivotY, x2, y2];
           } else {
              moveAllCoincident(x1, y1, pivotX - len/2, pivotY, [s.id]);
              moveAllCoincident(x2, y2, pivotX + len/2, pivotY, [s.id]);
              s.points = [pivotX - len/2, pivotY, pivotX + len/2, pivotY];
           }
        }
      }
      updated[idx] = s;
      break;
    }

    case 'coincide': {
      if (!v1 || !v2) break;
      
      const fix1 = isFixed(v1);
      const fix2 = isFixed(v2);

      if (fix1 && fix2) {
         error = "Conflict: Both points are fixed/anchored.";
         break;
      }
      
      const movePoint = (vRef, targetX, targetY) => {
         const idx = findIdx(vRef.sketchId);
         if (idx === -1) return;
         const s = { ...updated[idx] };
         moveAllCoincident(vRef.x, vRef.y, targetX, targetY, [s.id]);
         if (s.type === 'line') {
           if (vRef.part === 'start') s.points = [targetX, targetY, s.points[2], s.points[3]];
           else if (vRef.part === 'end') s.points = [s.points[0], s.points[1], targetX, targetY];
           else {
             // Handle midpoints or generic edge points by translating the entire segment
             const dx = targetX - vRef.x;
             const dy = targetY - vRef.y;
             s.points = [s.points[0] + dx, s.points[1] + dy, s.points[2] + dx, s.points[3] + dy];
           }
         } else if (s.type === 'circle') {
           s.center = [targetX, targetY];
         } else if (s.type === 'rect') {
           const dx = targetX - vRef.x;
           const dy = targetY - vRef.y;
           s.start = [s.start[0] + dx, s.start[1] + dy];
           s.end = [s.end[0] + dx, s.end[1] + dy];
         }
         updated[idx] = s;
      };

      if (fix1 && !fix2) {
         const targetX = v1.type === 'origin' ? 0 : v1.x;
         const targetY = v1.type === 'origin' ? 0 : v1.y;
         movePoint(v2, targetX, targetY);
      } else if (!fix1 && fix2) {
         const targetX = v2.type === 'origin' ? 0 : v2.x;
         const targetY = v2.type === 'origin' ? 0 : v2.y;
         movePoint(v1, targetX, targetY);
      } else {
         const targetX = (v1.x + v2.x) / 2;
         const targetY = (v1.y + v2.y) / 2;
         movePoint(v1, targetX, targetY);
         movePoint(v2, targetX, targetY);
      }
      break;
    }

    case 'equal': {
      if (!v1 || !v2) return updated;
      const idx1 = findIdx(v1.sketchId);
      const idx2 = findIdx(v2.sketchId);
      if (idx1 === -1 || idx2 === -1) return updated;
      
      const s1 = updated[idx1];
      const s2 = { ...updated[idx2] };

      // Get reference length/radius from s1
      let refLen = 0;
      if (s1.type === 'line') refLen = Math.sqrt(Math.pow(s1.points[2]-s1.points[0], 2) + Math.pow(s1.points[3]-s1.points[1], 2));
      else if (s1.type === 'circle') refLen = s1.radius;

      // Apply to s2
      if (s2.type === 'line') {
         const dx = s2.points[2] - s2.points[0];
         const dy = s2.points[3] - s2.points[1];
         const curLen = Math.sqrt(dx*dx + dy*dy);
         if (curLen > 0) {
            const ratio = refLen / curLen;
            s2.points = [s2.points[0], s2.points[1], s2.points[0] + dx * ratio, s2.points[1] + dy * ratio];
         }
      } else if (s2.type === 'circle') {
         s2.radius = refLen;
      }
      updated[idx2] = s2;
      break;
    }

    case 'parallel':
    case 'perpendicular': {
      if (!v1 || !v2) return updated;
      const idx1 = findIdx(v1.sketchId);
      const idx2 = findIdx(v2.sketchId);
      if (idx1 === -1 || idx2 === -1) return updated;
      
      const s1 = updated[idx1];
      const s2 = { ...updated[idx2] };
      if (s1.type !== 'line' || s2.type !== 'line') return updated;

      const angle1 = Math.atan2(s1.points[3] - s1.points[1], s1.points[2] - s1.points[0]);
      let targetAngle = type === 'parallel' ? angle1 : angle1 + Math.PI / 2;

      const midX = (s2.points[0] + s2.points[2]) / 2;
      const midY = (s2.points[1] + s2.points[3]) / 2;
      const len = Math.sqrt(Math.pow(s2.points[2]-s2.points[0], 2) + Math.pow(s2.points[3]-s2.points[1], 2)) / 2;

      const newX1 = midX - Math.cos(targetAngle) * len;
      const newY1 = midY - Math.sin(targetAngle) * len;
      const newX2 = midX + Math.cos(targetAngle) * len;
      const newY2 = midY + Math.sin(targetAngle) * len;

      moveAllCoincident(s2.points[0], s2.points[1], newX1, newY1, [s2.id]);
      moveAllCoincident(s2.points[2], s2.points[3], newX2, newY2, [s2.id]);

      s2.points = [newX1, newY1, newX2, newY2];
      updated[idx2] = s2;
      break;
    }

    default: break;
  }

  if (!error) {
     const valErrors = validateConstraints(sketches, updated, dimensions, fixedPoints, referenceVertices, SCALE_M);
     if (valErrors.length > 0) {
        error = "Constraint Conflict:\n" + valErrors.map(e => " - " + e).join("\n");
     }
  }

  return { sketches: error ? sketches : updated, error };
};
